{
    "level": "A2",
    "intro": "In this topic you will learn how to use <strong>somewhere, anywhere, nowhere, everywhere</strong> correctly in affirmations, negations and questions.",
    "rules": [
        {
            "label": "Assertions",
            "color": "emerald",
            "text": "<strong>Somewhere</strong> - "somewhere" in statements:",
            "example": "I live somewhere near here."
        },
        {
            "label": "Objections / questions",
            "color": "blue",
            "text": "<strong>Anywhere</strong> - in objections and questions:",
            "example": "I don’t live anywhere near here."
        },
        {
            "label": "One word objection",
            "color": "rose",
            "text": "<strong>Nowhere</strong> - one word objection:",
            "example": "I live nowhere near here."
        }
    ]
}

{
    "title": "1. Forms and Translation",
    "intro": "Here are the four main place words from <code class="font-mono text-xs">some / any</code>:",
    "items": [
        {
            "label": "Assertion",
            "title": "somewhere",
            "subtitle": "somewhere"
        },
        {
            "label": "Negation / question",
            "title": "anywhere",
            "subtitle": "somewhere / nowhere (in objections and questions)"
        },
        {
            "label": "Negation",
            "title": "nowhere",
            "subtitle": "nowhere"
        },
        {
            "label": "Generalization",
            "title": "everywhere",
            "subtitle": "everywhere"
        }
    ]
}

{
    "title": "2. Use in affirmations, objections and questions",
    "sections": [
        {
            "label": "Ствердження (Affirmative)",
            "color": "emerald",
            "description": "У ствердженнях частіше вживаємо <strong>somewhere</strong> та <strong>everywhere</strong>.",
            "examples": [
                {
                    "en": "He is somewhere in the building.",
                    "ua": "Він десь у будівлі."
                },
                {
                    "en": "You can see flowers everywhere in spring.",
                    "ua": "Навесні квіти видно всюди."
                }
            ]
        },
        {
            "label": "Заперечення (Negative)",
            "color": "rose",
            "description": "У запереченні вживаємо <strong>anywhere</strong> з <code class="font-mono text-xs">don’t/doesn’t</code> або <strong>nowhere</strong> без додаткового not.",
            "examples": [
                {
                    "en": "I don’t go anywhere on Sundays.",
                    "ua": "I don’t go anywhere on Sundays."
                },
                {
                    "en": "I go nowhere on Sundays.",
                    "ua": "I don’t go anywhere on Sundays."
                }
            ],
            "note": "❗ Avoid double negatives like <span class="line-through">I don’t go nowhere</span>."
        },
        {
            "label": "Questions",
            "color": "sky",
            "description": "In questions we usually use <strong>anywhere</strong>.",
            "examples": [
                {
                    "en": "Do you go anywhere on Sundays?",
                    "ua": "Do you go anywhere on Sundays?"
                },
                {
                    "en": "Is there anywhere to eat near here?",
                    "ua": "Is there somewhere to eat near here?"
                }
            ],
            "note": "<span class="font-semibold">Somewhere</span> in the question it sounds like you expect "some specific place"."
        }
    ]
}

{
    "title": "3. Anywhere vs Nowhere",
    "intro": "<strong>Two different grammatical forms - same meaning</strong> in normal English:",
    "rows": [
        {
            "en": "I don’t go anywhere on Sundays.",
            "ua": "I don’t go anywhere on Sundays.",
            "note": "Objection via <code class="font-mono text-xs">don't</code> + <strong>anywhere</strong>."
        },
        {
            "en": "I go nowhere on Sundays.",
            "ua": "I don't go anywhere on Sundays.",
            "note": "One-word objection <strong>nowhere</strong>, without <code class="font-mono text-xs">don't</code>."
        }
    ],
    "warning": "❗ <span class="line-through">I don’t go nowhere</span> is grammatically incorrect in standard English (it is a double negative)."
}

{
    "title": "4. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Double negation as in Ukrainian.",
            "wrong": "I don’t go nowhere.",
            "right": " ✅ <span class="font-mono">I don’t go anywhere.</span> / <span class="font-mono">I go nowhere.</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Confusion between <strong>somewhere</strong> and <strong>anywhere</strong> in questions.",
            "hint": "<span class="font-mono">Do you go somewhere on Sundays?</span> sounds like "to some specific place".<br>Usually better: <span class="font-mono">Do you go anywhere on Sundays?</span>"
        },
        {
            "label": "Mistake 3",
            "color": "sky",
            "title": "Using <strong>everywhere</strong> instead of <strong>somewhere</strong>.",
            "hint": "<span class="font-mono">I want to go everywhere in London.</span> — I want to go everywhere in London.<br>If simple "somewhere": <span class="font-mono">I want to go somewhere in London.</span>"
        }
    ]
}

{
    "title": "5. Brief synopsis",
    "items": [
        "<strong>Somewhere</strong> - "somewhere" in statements.",
        "<strong>Anywhere</strong> - "somewhere / nowhere" in objections and questions.",
        "<strong>Nowhere</strong> - "nowhere", objection by one in a word.",
        "<strong>Everywhere</strong> - "everywhere".",
        "Avoid double negation: not <span class="line-through">I don't go nowhere</span>, but <span class="font-mono text-xs">I don't go anywhere / I go nowhere</span>."
    ]
}

{
    "title": "6. Practice",
    "select_title": "Exercise 1. Choose the correct word",
    "select_intro": "Choose <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
    "selects": [
        {
            "label": "I can’t find my keys <span class="text-slate-500">(nowhere)</span>.",
            "prompt": "I can’t find my keys ______."
        },
        {
            "label": "She wants to live <span class="text-slate-500">(somewhere near the sea)</span>.",
            "prompt": "She wants to live ______ near the sea."
        },
        {
            "label": "Do you want to go <span class="text-slate-500">(somewhere)</span> this evening?",
            "prompt": "Do you want to go ______ this night? everywhere."
        }
    ],
    "options": [
        "somewhere",
        "anywhere",
        "nowhere",
        "everywhere"
    ],
    "input_title": "Вправа 2. Заповни пропуски",
    "input_intro": "Напиши <strong>somewhere / anywhere / nowhere / everywhere</strong>.",
    "inputs": [
        {
            "before": "I don’t want to go",
            "after": "tonight."
        },
        {
            "before": "There is",
            "after": "to sit in this park. it’s full. go anywhere on Saturdays."
        },
        {
            "before": "He travels",
            "after": "for work."
        }
    ],
    "rephrase_title": "Вправа 3. Перефразуй",
    "rephrase_intro": "Перепиши речення, використовуючи <strong>anywhere / nowhere</strong>.",
    "rephrase": [
        {
            "example_label": "Приклад:",
            "example_original": "I don’t go anywhere on Saturdays.",
            "example_target": "I go nowhere on Saturdays."
        },
        {
            "original": "1. I go nowhere on Friday evenings.",
            "placeholder": "Write the same thing, but with don’t... anywhere"
        },
        {
            "original": "2. She doesn’t go anywhere without her phone.",
            "placeholder": "Try paraphrasing with nowhere"
        }
    ]
}

{
    "title": "Other pages from the series Some / Any",
    "items": [
